package co.istad.makara.account.application;import co.istad.makara.account.application.dto.create.*;import co.istad.makara.account.application.mapper.AccountMapper;import co.istad.makara.account.application.ports.input.service.AccountService;import co.istad.makara.account.domain.command.CreateAccountCommand;import co.istad.makara.account.domain.command.DepositMoneyCommand;import co.istad.makara.account.domain.command.FreezeAccountCommand;import co.istad.makara.account.domain.command.WithdrawMoneyCommand;import co.istad.makara.common.domain.valueobject.AccountId;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.axonframework.commandhandling.gateway.CommandGateway;import org.springframework.stereotype.Service;import java.util.UUID;@Service@Slf4j@RequiredArgsConstructorpublic class AccountServiceImpl implements AccountService {    private final AccountMapper accountMapper;    private final CommandGateway commandGateway;    @Override    public CreateAccountResponse createAccount(CreateAccountRequest createAccountRequest) {        log.info("CreateAccountRequest: {}", createAccountRequest);        CreateAccountCommand createAccountCommand = accountMapper.toCreateAccountCommand(                new AccountId(UUID.randomUUID()),                createAccountRequest);        AccountId accountId = commandGateway.sendAndWait(createAccountCommand);        return CreateAccountResponse.builder()                .accountId(accountId.value().toString())                .accountHolder(createAccountRequest.accountHolder())                .accountNumber(createAccountRequest.accountNumber())                .message("Account created successfully")                .build();    }    @Override    public CreateDepositResponse depositAmount(CreateDepositRequest request) {        log.info("CreateDepositRequest: {}", request);        DepositMoneyCommand depositMoneyCommand = accountMapper.toDepositMoneyCommand(                request.accountId(),                request.transactionId(),                request.amount(),                request.remark()        );        commandGateway.sendAndWait(depositMoneyCommand);        return CreateDepositResponse.builder()                .amount(request.amount())                .remark(request.remark())                .build();    }    @Override    public CreateWithdrawalResponse withdrawalAmount(CreateWithdrawalRequest request) {        log.info("CreateWithdrawalRequest: {}", request);        WithdrawMoneyCommand withdrawMoneyCommand = accountMapper.toWithdrawMoneyCommand(                request.accountId(),                request.transactionId(),                request.amount(),                request.remark()        );        commandGateway.sendAndWait(withdrawMoneyCommand);        return CreateWithdrawalResponse.builder()                .amount(request.amount())                .remark(request.remark())                .build();    }    @Override    public CreateFrozenResponse freezeAccount(CreateFrozenRequest request) {        log.info("CreateFrozenRequest: {}", request);        FreezeAccountCommand command = new FreezeAccountCommand(            request.accountId(),            request.remark(),            request.requestedBy()        );        commandGateway.sendAndWait(command);        return CreateFrozenResponse.builder()                .accountId(request.accountId())                .remark(request.remark())                .build();    }}